int bmp_validate(jas_stream_t *in)
{
    uchar buf[2];
    int n = jas_stream_read(in, (char*)buf, 2);
    if (n != 2) return -1;

    /* Prefer seek back if possible */
    if (jas_stream_seek(in, -2, SEEK_CUR) < 0) {
        /* Fallback: only if guaranteed putback >= 2 at runtime */
        if (jas_stream_ungetc(in, buf[1]) == EOF) return -1;
        if (jas_stream_ungetc(in, buf[0]) == EOF) return -1;
